390	    pub async fn from_config(
391	        mut self,
392	        config: &ExpandedConfig,
393	    ) -> ZResult<TransportManagerBuilder> {
394	        self = self.zid(config.id().into());
395	        self = self.whatami(config.mode());
396	
397	        let link = config.transport().link();
398	        let cc_drop = link.tx().queue().congestion_control().drop();
399	        let cc_block = link.tx().queue().congestion_control().block();
400	        let mut resolution = Resolution::default();
401	        resolution.set(Field::FrameSN, *link.tx().sequence_number_resolution());
402	        self = self.resolution(resolution);
403	        self = self.batch_size(*link.tx().batch_size());
404	        self = self.batching_enabled(*link.tx().queue().batching().enabled());
405	        self = self.batching_time_limit(Duration::from_millis(
406	            *link.tx().queue().batching().time_limit(),
407	        ));
408	        self = self.defrag_buff_size(*link.rx().max_message_size());
409	        self = self.link_rx_buffer_size(*link.rx().buffer_size());
410	        self = self.wait_before_drop(duration_from_i64us(*cc_drop.wait_before_drop()));
411	        self = self.max_wait_before_drop_fragments(duration_from_i64us(
412	            *cc_drop.max_wait_before_drop_fragments(),
413	        ));
414	        self = self.wait_before_close(duration_from_i64us(*cc_block.wait_before_close()));
415	        self = self.queue_size(link.tx().queue().size().clone());
416	        self = self.queue_alloc(*link.tx().queue().allocation());
417	        self = self.tx_threads(*link.tx().threads());
418	        self = self.protocols(link.protocols().clone());
419	        self = self.region_name(config.region_name().clone());
420	
421	        #[cfg(feature = "shared-memory")]
422	        {
423	            self = self.shm(config.transport().shared_memory().clone());
424	        }
425	
426	        let (c, errors) = zenoh_link::LinkConfigurator::default().configurations(config);
427	        if !errors.is_empty() {
428	            use std::fmt::Write;
429	            let mut formatter = String::from("Some protocols reported configuration errors:\r\n");
430	            for (proto, err) in errors {
431	                write!(&mut formatter, "\t{proto:?}: {err}\r\n")?;
432	            }
433	            bail!("{}", formatter);
434	        }
435	        self = self.link_configs(c);
436	        self = self.unicast(
437	            TransportManagerBuilderUnicast::default()
438	                .from_config(config)
439	                .await?,
440	        );
441	        self = self.multicast(TransportManagerBuilderMulticast::default().from_config(config)?);
442	
443	        Ok(self)
444	    }
445	
446	    pub fn build(
447	        self,
448	        handler: Arc<dyn TransportEventHandler>,
449	        #[cfg(feature = "stats")] stats: zenoh_stats::StatsRegistry,
450	    ) -> ZResult<TransportManager> {
451	        // Initialize the PRNG and the Cipher
452	        let mut prng = PseudoRng::from_entropy();
453	
454	        #[cfg(feature = "shared-memory")]
455	        let shm_context = ShmContext::new(self.shm, self.shm_reader)?;
456	
457	        let unicast = self.unicast.build(&mut prng)?;
458	        let multicast = self.multicast.build()?;
459	
460	        let mut queue_size = [0; Priority::NUM];
461	        queue_size[Priority::Control as usize] = *self.queue_size.control();
462	        queue_size[Priority::RealTime as usize] = *self.queue_size.real_time();
463	        queue_size[Priority::InteractiveHigh as usize] = *self.queue_size.interactive_high();
464	        queue_size[Priority::InteractiveLow as usize] = *self.queue_size.interactive_low();
465	        queue_size[Priority::DataHigh as usize] = *self.queue_size.data_high();
466	        queue_size[Priority::Data as usize] = *self.queue_size.data();
467	        queue_size[Priority::DataLow as usize] = *self.queue_size.data_low();
468	        queue_size[Priority::Background as usize] = *self.queue_size.background();
469	
470	        let config = TransportManagerConfig {
471	            version: self.version,
472	            zid: self.zid,
473	            whatami: self.whatami,
474	            resolution: self.resolution,
475	            batch_size: self.batch_size,
476	            batching: self.batching_enabled,
477	            wait_before_drop: self.wait_before_drop,
478	            max_wait_before_drop_fragments: self.max_wait_before_drop_fragments,
479	            wait_before_close: self.wait_before_close,
480	            queue_size,
481	            queue_backoff: self.batching_time_limit,
482	            queue_alloc: self.queue_alloc,
483	            defrag_buff_size: self.defrag_buff_size,
484	            link_rx_buffer_size: self.link_rx_buffer_size,
485	            unicast: unicast.config,
486	            multicast: multicast.config,
487	            link_configs: self.link_configs,
488	            handler,
489	            tx_threads: self.tx_threads,
490	            supported_links: self
491	                .supported_links
492	                .unwrap_or_else(|| zenoh_link::ALL_SUPPORTED_LINKS.to_vec()),
493	            bound_callback: self.bound_callback,
494	            region_name: self.region_name,
495	        };
496	
497	        let state = TransportManagerState {
498	            unicast: unicast.state,
499	            multicast: multicast.state,
500	            #[cfg(feature = "shared-memory")]
501	            shm_context,
502	        };
503	
504	        let params = TransportManagerParams { config, state };
505	
506	        Ok(TransportManager::new(
507	            params,
508	            prng,
509	            #[cfg(feature = "stats")]
510	            stats,
511	        ))
512	    }
513	
514	    #[cfg(feature = "test")]
515	    pub fn build_test(self, handler: Arc<dyn TransportEventHandler>) -> ZResult<TransportManager> {
516	        #[cfg(feature = "stats")]
517	        let stats = zenoh_stats::StatsRegistry::new(self.zid, self.whatami, "test");
518	        self.build(
519	            handler,
520	            #[cfg(feature = "stats")]
521	            stats,
522	        )
523	    }
524	}
