540	            wait_before_drop: duration_from_i64us(*cc_drop.wait_before_drop()),
541	            max_wait_before_drop_fragments: duration_from_i64us(
542	                *cc_drop.max_wait_before_drop_fragments(),
543	            ),
544	            wait_before_close: duration_from_i64us(*cc_block.wait_before_close()),
545	            queue_size: queue.size,
