555	            region_name: None,
556	            bound_callback: None,
557	            #[cfg(feature = "shared-memory")]
558	            shm: zenoh_config::ShmConf::default(),
559	            #[cfg(feature = "shared-memory")]
560	            shm_reader: None,
561	        }
562	    }
563	}
