568	    pub(crate) state: Arc<TransportManagerState>,
569	    pub(crate) prng: Arc<AsyncMutex<PseudoRng>>,
570	    pub(crate) cipher: Arc<BlockCipher>,
571	    pub(crate) locator_inspector: zenoh_link::LocatorInspector,
572	    pub(crate) new_unicast_link_sender: NewLinkChannelSender,
