596	impl TransportManager {
597	    pub fn new(
598	        params: TransportManagerParams,
599	        mut prng: PseudoRng,
600	        #[cfg(feature = "stats")] stats: zenoh_stats::StatsRegistry,
601	    ) -> TransportManager {
602	        // Initialize the Cipher
603	        let mut key = [0_u8; BlockCipher::BLOCK_SIZE];
604	        prng.fill_bytes(&mut key);
605	        let cipher = BlockCipher::new(key);
606	
607	        // @TODO: this should be moved into the unicast module
608	        let (new_unicast_link_sender, new_unicast_link_receiver) = flume::unbounded();
609	
610	        let this = TransportManager {
611	            config: Arc::new(params.config),
612	            state: Arc::new(params.state),
613	            prng: Arc::new(AsyncMutex::new(prng)),
614	            cipher: Arc::new(cipher),
615	            locator_inspector: Default::default(),
616	            new_unicast_link_sender,
617	            #[cfg(feature = "stats")]
618	            stats,
619	            task_controller: TaskController::default(),
620	        };
621	
622	        // @TODO: this should be moved into the unicast module
623	        let cancellation_token = this.task_controller.get_cancellation_token();
624	        this.task_controller
625	            .spawn_with_rt(zenoh_runtime::ZRuntime::Net, {
626	                let this = this.clone();
627	                async move {
628	                    loop {
629	                        tokio::select! {
630	                                res = new_unicast_link_receiver.recv_async() => {
631	                                    if let Ok(new_link) = res {
632	                                        this.handle_new_link_unicast(new_link).await;
633	                                    }
634	                                }
635	                                _ = cancellation_token.cancelled() => { break; }
636	                        }
637	                    }
638	                }
639	            });
640	
641	        this
642	    }
643	
644	    pub fn builder() -> TransportManagerBuilder {
645	        TransportManagerBuilder::default()
646	    }
