669	    /*              LISTENER             */
670	    /*************************************/
671	    pub async fn add_listener(&self, endpoint: EndPoint) -> ZResult<Locator> {
672	        if self
673	            .locator_inspector
674	            .is_multicast(&endpoint.to_locator())
675	            .await?
676	        {
677	            self.add_listener_multicast(endpoint).await
678	        } else {
679	            self.add_listener_unicast(endpoint).await
680	        }
681	    }
682	
683	    pub async fn del_listener(&self, endpoint: &EndPoint) -> ZResult<()> {
684	        if self
685	            .locator_inspector
686	            .is_multicast(&endpoint.to_locator())
687	            .await?
688	        {
689	            self.del_listener_multicast(endpoint).await
690	        } else {
691	            self.del_listener_unicast(endpoint).await
692	        }
693	    }
694	
695	    pub async fn get_listeners(&self) -> Vec<EndPoint> {
696	        let mut lsu = self.get_listeners_unicast().await;
697	        let mut lsm = self.get_listeners_multicast().await;
698	        lsu.append(&mut lsm);
699	        lsu
700	    }
