702	    // TODO(yuyuan): Can we make this async as above?
703	    pub fn get_locators(&self) -> Vec<Locator> {
704	        let mut lsu = zenoh_runtime::ZRuntime::Net.block_in_place(self.get_locators_unicast());
705	        let mut lsm = zenoh_runtime::ZRuntime::Net.block_in_place(self.get_locators_multicast());
706	        lsu.append(&mut lsm);
707	        lsu
708	    }
709	}
