355	    pub async fn close_unicast(&self) {
356	        tracing::trace!("TransportManagerUnicast::clear()");
357	
358	        let mut pl_guard = zasynclock!(self.state.unicast.link_managers)
359	            .drain()
360	            .map(|(_, v)| v)
361	            .collect::<Vec<Arc<dyn LinkManagerUnicastTrait>>>();
362	
363	        for pl in pl_guard.drain(..) {
364	            for ep in pl.get_listeners().await.iter() {
365	                let _ = pl.del_listener(ep).await;
366	            }
367	        }
368	
369	        let mut tu_guard = zasynclock!(self.state.unicast.transports)
370	            .drain()
371	            .map(|(_, v)| v)
372	            .collect::<Vec<Arc<dyn TransportUnicastTrait>>>();
373	        for tu in tu_guard.drain(..) {
374	            let _ = tu.close(close::reason::GENERIC).await;
375	        }
