381	    async fn new_link_manager_unicast(&self, endpoint: &EndPoint) -> ZResult<LinkManagerUnicast> {
382	        let protocol = endpoint.protocol().as_str();
383	        let link_kind = LinkKind::try_from(endpoint)?;
384	        if !self.config.supported_links.contains(&link_kind) {
385	            bail!(
386	                "Unsupported protocol: {}. Supported protocols are: {:?}",
387	                protocol,
388	                self.config.supported_links
389	            );
390	        }
391	
392	        let mut w_guard = zasynclock!(self.state.unicast.link_managers);
393	        let key = LinkKey::from(endpoint);
394	        if let Some(lm) = w_guard.get(&key) {
395	            Ok(lm.clone())
396	        } else {
397	            let lm =
398	                LinkManagerBuilderUnicast::make(self.new_unicast_link_sender.clone(), endpoint)?;
399	            w_guard.insert(key, lm.clone());
400	            Ok(lm)
401	        }
402	    }
