427	    pub async fn add_listener_unicast(&self, mut endpoint: EndPoint) -> ZResult<Locator> {
428	        if self
429	            .locator_inspector
430	            .is_multicast(&endpoint.to_locator())
431	            .await?
432	        {
433	            bail!(
434	                "Can not listen on unicast endpoint with a multicast endpoint: {}.",
435	                endpoint
436	            )
437	        }
438	
439	        let manager = self.new_link_manager_unicast(&endpoint).await?;
440	        // Fill and merge the endpoint configuration
441	        if let Some(config) = self
442	            .config
443	            .link_configs
444	            .get(&LinkKind::try_from(&endpoint)?)
445	        {
446	            let mut config = parameters::Parameters::from(config.as_str());
447	            // Overwrite config with current endpoint parameters
448	            config.extend_from_iter(endpoint.config().iter());
449	            endpoint = EndPoint::new(
450	                endpoint.protocol(),
451	                endpoint.address(),
452	                endpoint.metadata(),
453	                config.as_str(),
454	            )?;
