487	    async fn init_existing_transport_unicast(
488	        &self,
489	        config: TransportConfigUnicast,
490	        link: LinkUnicastWithOpenAck,
491	        other_initial_sn: TransportSn,
492	        other_lease: Duration,
493	        transport: Arc<dyn TransportUnicastTrait>,
494	    ) -> InitTransportResult {
495	        let existing_config = transport.get_config();
496	        // Verify that fundamental parameters are correct.
497	        // Ignore the non fundamental parameters like initial SN.
498	        if *existing_config != config {
499	            let e = zerror!(
500	                "Transport with peer {} already exist. Invalid config: {:?}. Expected: {:?}.",
501	                config.zid,
502	                config,
503	                existing_config
504	            );
505	            tracing::trace!("{}", e);
506	            let (l, asl) = link.fail();
507	            return Err(InitTransportError::Link((
508	                e.into(),
509	                l,
510	                asl,
511	                close::reason::INVALID,
512	            )));
513	        }
514	
515	        // Add the link to the transport
516	        let (start_tx, start_rx, ack, add_link_guard) = transport
517	            .add_link(link, other_initial_sn, other_lease)
518	            .await
519	            .map_err(InitTransportError::Link)?;
520	
521	        // complete establish procedure
522	        let c_link = ack.link();
523	        ack.send_open_ack().await.map_err(|e| {
524	            InitTransportError::Transport((e, transport.clone(), close::reason::GENERIC))
525	        })?;
526	
527	        start_tx();
528	
529	        // notify transport's callback interface that there is a new link
530	        Self::notify_new_link_unicast(&transport, c_link)
531	            .await
532	            .map_err(|e| {
533	                InitTransportError::Transport((e, transport.clone(), close::reason::GENERIC))
534	            })?;
535	
536	        start_rx();
537	
538	        drop(add_link_guard);
539	
540	        Ok(transport)
541	    }
542	
543	    async fn notify_new_link_unicast(
544	        transport: &Arc<dyn TransportUnicastTrait>,
545	        link: Link,
546	    ) -> ZResult<()> {
547	        if let Some(callback) = transport.get_callback() {
548	            tokio::task::spawn_blocking(move || {
549	                callback.new_link(link);
550	            })
551	            .await?;
552	        }
553	
554	        Ok(())
555	    }
556	
557	    fn notify_new_transport_unicast(
558	        &self,
559	        transport: &Arc<dyn TransportUnicastTrait>,
560	    ) -> ZResult<()> {
561	        // Assign a callback to the new transport
562	        let peer = TransportPeer {
563	            zid: transport.get_zid(),
564	            whatami: transport.get_whatami(),
565	            links: transport.get_links(),
566	            is_qos: transport.get_config().is_qos,
567	            #[cfg(feature = "shared-memory")]
568	            is_shm: transport.is_shm(),
569	            region_name: transport.region_name(),
570	        };
571	        // Notify the transport handler that there is a new transport and get back a callback
572	        // NOTE: the read loop of the link the open message was sent on remains blocked
573	        //       until new_unicast() returns. The read_loop in the various links
574	        //       waits for any eventual transport to associate to.
575	        let callback = self
576	            .config
577	            .handler
578	            .new_unicast(peer, TransportUnicast(Arc::downgrade(transport)))?;
579	
580	        // Set the callback on the transport
581	        transport.set_callback(callback);
582	
583	        Ok(())
584	    }
585	
586	    pub(super) async fn init_new_transport_unicast(
587	        &self,
588	        config: TransportConfigUnicast,
589	        link: LinkUnicastWithOpenAck,
590	        other_initial_sn: TransportSn,
591	        other_lease: Duration,
592	        mut guard: AsyncMutexGuard<'_, HashMap<ZenohIdProto, Arc<dyn TransportUnicastTrait>>>,
593	    ) -> InitTransportResult {
594	        macro_rules! link_error {
595	            ($s:expr, $reason:expr) => {
596	                match $s {
597	                    Ok(output) => output,
598	                    Err(e) => {
599	                        let (l, asl) = link.fail();
600	                        return Err(InitTransportError::Link((e, l, asl, $reason)));
601	                    }
602	                }
603	            };
604	        }
605	
606	        // Verify that the node does not try to connect to itself
607	        if config.zid == self.zid() {
608	            let e = zerror!("{} Attempt to establish transport to itself", self.zid());
609	            tracing::warn!("{e}");
610	            let (l, asl) = link.fail();
611	            return Err(InitTransportError::Link((
612	                e.into(),
613	                l,
614	                asl,
615	                close::reason::CONNECTION_TO_SELF,
616	            )));
617	        }
618	
619	        // Verify that we haven't reached the transport number limit
620	        if guard.len() >= self.config.unicast.max_sessions {
621	            let e = zerror!(
622	                "Max transports reached ({}). Denying new transport with peer: {}",
623	                self.config.unicast.max_sessions,
624	                config.zid
625	            );
626	            tracing::trace!("{e}");
627	            let (l, asl) = link.fail();
628	            return Err(InitTransportError::Link((
629	                e.into(),
630	                l,
631	                asl,
632	                close::reason::INVALID,
633	            )));
634	        }
635	
636	        // Create the transport
637	        let is_multilink = zcondfeat!("transport_multilink", config.multilink.is_some(), false);
638	
639	        #[cfg(feature = "stats")]
640	        let stats = self.stats.unicast_transport_stats(
641	            config.zid,
642	            config.whatami,
643	            link.link
644	                .link
645	                .get_auth_id()
646	                .get_cert_common_name()
647	                .map(Into::into),
648	        );
649	
650	        #[cfg(feature = "shared-memory")]
651	        let shm_context = match &config.shm {
652	            Some(shm_config) => self.state.shm_context.as_ref().map(|context| {
653	                use zenoh_shm::api::protocol_implementations::posix::protocol_id::POSIX_PROTOCOL_ID;
654	
655	                use crate::{shm::PartnerShmConfig, shm_context::UnicastTransportShmContext};
656	
657	                let shm_provider = if shm_config.supports_protocol(POSIX_PROTOCOL_ID) {
658	                    context.shm_provider.clone()
659	                } else {
660	                    None
661	                };
662	
663	                UnicastTransportShmContext::new(
664	                    context.shm_reader.clone(),
665	                    shm_provider,
666	                    shm_config.clone(),
667	                )
668	            }),
669	            None => None,
670	        };
671	
672	        // Select and create transport implementation depending on the cfg and enabled features
673	        let t = if config.is_lowlatency {
674	            tracing::debug!("Will use LowLatency transport!");
675	            TransportUnicastLowlatency::make(
676	                self.clone(),
677	                config.clone(),
678	                #[cfg(feature = "shared-memory")]
679	                shm_context,
680	                #[cfg(feature = "stats")]
681	                stats,
682	            )
683	        } else {
684	            tracing::debug!("Will use Universal transport!");
685	            link_error!(
686	                TransportUnicastUniversal::make(
687	                    self.clone(),
688	                    config.clone(),
689	                    #[cfg(feature = "shared-memory")]
690	                    shm_context,
691	                    #[cfg(feature = "stats")]
692	                    stats
693	                ),
694	                close::reason::INVALID
695	            )
696	        };
697	
698	        // Add the link to the transport
699	        let (start_tx, start_rx, ack, add_link_guard) =
700	            match t.add_link(link, other_initial_sn, other_lease).await {
701	                Ok(val) => val,
702	                Err(e) => {
703	                    let _ = t.close(e.3).await;
704	                    return Err(InitTransportError::Link(e));
705	                }
706	            };
707	
708	        macro_rules! transport_error {
709	            ($s:expr, $reason:expr) => {
710	                match $s {
711	                    Ok(output) => output,
712	                    Err(e) => {
713	                        return Err(InitTransportError::Transport((e, t.clone(), $reason)));
714	                    }
715	                }
716	            };
717	        }
718	
719	        // Complete establish procedure
720	        let c_link = ack.link();
721	        transport_error!(ack.send_open_ack().await, close::reason::GENERIC);
722	
723	        // Add the transport transport to the list of active transports
724	        guard.insert(config.zid, t.clone());
725	        drop(guard);
726	
727	        start_tx();
728	
729	        // Notify manager's interface that there is a new transport
730	        transport_error!(
731	            self.notify_new_transport_unicast(&t),
732	            close::reason::GENERIC
733	        );
734	
735	        // Notify transport's callback interface that there is a new link
736	        transport_error!(
737	            Self::notify_new_link_unicast(&t, c_link).await,
738	            close::reason::GENERIC
739	        );
740	
741	        start_rx();
742	
743	        drop(add_link_guard);
744	
745	        zcondfeat!(
746	            "shared-memory",
747	            {
748	                tracing::debug!(
749	            "New transport opened between {} and {} - whatami: {}, sn resolution: {:?}, initial sn: {:?}, qos: {}, shm: {:?}, multilink: {}, lowlatency: {}",
750	            self.config.zid,
751	            config.zid,
752	            config.whatami,
753	            config.sn_resolution,
754	            config.tx_initial_sn,
755	            config.is_qos,
756	            config.shm,
757	            is_multilink,
758	            config.is_lowlatency
759	        );
760	            },
761	            {
762	                tracing::debug!(
763	            "New transport opened between {} and {} - whatami: {}, sn resolution: {:?}, initial sn: {:?}, qos: {:?}, multilink: {}, lowlatency: {}",
764	            self.config.zid,
765	            config.zid,
766	            config.whatami,
767	            config.sn_resolution,
768	            config.tx_initial_sn,
769	            config.is_qos,
770	            is_multilink,
771	            config.is_lowlatency
772	        );
773	            }
774	        );
775	
776	        Ok(t)
777	    }
778	
779	    pub(super) async fn init_transport_unicast(
780	        &self,
781	        config: TransportConfigUnicast,
782	        link: LinkUnicastWithOpenAck,
783	        other_initial_sn: TransportSn,
784	        other_lease: Duration,
785	    ) -> ZResult<TransportUnicast> {
786	        // First verify if the transport already exists
787	        let init_result = {
788	            let guard = zasynclock!(self.state.unicast.transports);
789	            match guard.get(&config.zid) {
790	                Some(transport) => {
791	                    let transport = transport.clone();
792	                    drop(guard);
793	                    self.init_existing_transport_unicast(
794	                        config,
795	                        link,
796	                        other_initial_sn,
797	                        other_lease,
798	                        transport,
799	                    )
800	                    .await
801	                }
802	                None => {
803	                    self.init_new_transport_unicast(
804	                        config,
805	                        link,
806	                        other_initial_sn,
807	                        other_lease,
808	                        guard,
809	                    )
810	                    .await
811	                }
812	            }
813	        };
814	
815	        match init_result {
816	            Ok(transport) => Ok(TransportUnicast(Arc::downgrade(&transport))),
817	            Err(InitTransportError::Link((e, link, associated_link, reason))) => {
818	                let _ = link.close(Some(reason)).await;
819	                if let Some(asl) = associated_link {
820	                    let _ = asl.close(Some(reason)).await;
821	                }
822	                Err(e)
823	            }
824	            Err(InitTransportError::Transport((e, transport, reason))) => {
825	                let _ = transport.close(reason).await;
826	                Err(e)
827	            }
828	        }
829	    }
830	
831	    pub async fn open_transport_unicast(&self, endpoint: EndPoint) -> ZResult<TransportUnicast> {
832	        self.open_transport_unicast_inner(endpoint, None).await
833	    }
834	
835	    pub async fn open_transport_unicast_with_zid(
836	        &self,
837	        endpoint: EndPoint,
838	        expected_zid: &ZenohIdProto,
839	    ) -> ZResult<TransportUnicast> {
840	        self.open_transport_unicast_inner(endpoint, Some(expected_zid))
841	            .await
842	    }
843	
844	    async fn open_transport_unicast_inner(
845	        &self,
846	        mut endpoint: EndPoint,
847	        expected_zid: Option<&ZenohIdProto>,
848	    ) -> ZResult<TransportUnicast> {
849	        if self
850	            .locator_inspector
851	            .is_multicast(&endpoint.to_locator())
852	            .await?
853	        {
854	            bail!(
855	                "Can not open a unicast transport with a multicast endpoint: {}.",
856	                endpoint
857	            )
858	        }
859	
860	        // Automatically create a new link manager for the protocol if it does not exist
861	        let manager = self.new_link_manager_unicast(&endpoint).await?;
862	        // Fill and merge the endpoint configuration
863	        if let Some(config) = self
864	            .config
865	            .link_configs
866	            .get(&LinkKind::try_from(&endpoint)?)
867	        {
868	            let mut config = parameters::Parameters::from(config.as_str());
869	            // Overwrite config with current endpoint parameters
870	            config.extend_from_iter(endpoint.config().iter());
871	            endpoint = EndPoint::new(
872	                endpoint.protocol(),
873	                endpoint.address(),
874	                endpoint.metadata(),
875	                config.as_str(),
876	            )?;
877	        };
878	
879	        // Open the link
880	        tokio::time::timeout(self.config.unicast.open_timeout, async {
881	            match manager.new_link(endpoint.clone()).await {
882	                Ok(link) => {
883	                    super::establishment::open::open_link(endpoint, link, self, expected_zid).await
884	                }
885	                Err(e) => Err(e),
886	            }
887	        })
888	        .await
889	        .map_err(|e| zerror!("{e}"))?
890	    }
891	
892	    pub async fn get_transport_unicast(&self, peer: &ZenohIdProto) -> Option<TransportUnicast> {
893	        zasynclock!(self.state.unicast.transports)
894	            .get(peer)
895	            .map(|t| TransportUnicast(Arc::downgrade(t)))
896	    }
897	
898	    pub async fn get_transports_unicast(&self) -> Vec<TransportUnicast> {
899	        zasynclock!(self.state.unicast.transports)
900	            .values()
901	            .map(|t| TransportUnicast(Arc::downgrade(t)))
902	            .collect()
903	    }
904	
905	    pub fn get_transports_unicast_blocking(&self) -> Vec<TransportUnicast> {
906	        self.state
907	            .unicast
908	            .transports
909	            .blocking_lock()
910	            .values()
911	            .map(|t| TransportUnicast(Arc::downgrade(t)))
912	            .collect()
913	    }
914	
915	    pub(super) async fn del_transport_unicast(&self, peer: &ZenohIdProto) -> ZResult<()> {
916	        zasynclock!(self.state.unicast.transports)
917	            .remove(peer)
918	            .ok_or_else(|| {
919	                let e = zerror!("Can not delete the transport of peer: {}", peer);
920	                tracing::trace!("{}", e);
921	                e
922	            })?;
923	        Ok(())
924	    }
925	
926	    pub(crate) async fn handle_new_link_unicast(&self, link: LinkUnicast) {
927	        let incoming_counter = self.state.unicast.incoming.clone();
928	        if incoming_counter.load(SeqCst) >= self.config.unicast.accept_pending {
929	            // We reached the limit of concurrent incoming transport, this means two things:
930	            // - the values configured for ZN_OPEN_INCOMING_PENDING and ZN_OPEN_TIMEOUT
931	            //   are too small for the scenario zenoh is deployed in;
932	            // - there is a tentative of DoS attack.
933	            // In both cases, let's close the link straight away with no additional notification
934	            tracing::trace!("Closing link for preventing potential DoS: {}", link);
935	            let _ = link.close().await;
936	            return;
937	        }
938	
939	        // A new link is available
940	        tracing::trace!("Accepting link... {}", link);
941	        self.state.unicast.incoming.fetch_add(1, SeqCst);
942	
943	        // Spawn a task to accept the link
944	        let c_manager = self.clone();
945	        self.task_controller
946	            .spawn_with_rt(zenoh_runtime::ZRuntime::Acceptor, async move {
947	                if tokio::time::timeout(
948	                    c_manager.config.unicast.accept_timeout,
949	                    super::establishment::accept::accept_link(link, &c_manager),
950	                )
951	                .await
952	                .is_err()
953	                {
954	                    tracing::debug!(
955	                        "Failed to accept link before deadline ({}ms)",
956	                        c_manager.config.unicast.accept_timeout.as_millis()
957	                    );
958	                }
959	                incoming_counter.fetch_sub(1, SeqCst);
960	            });
961	    }
962	}
963	
964	#[cfg(all(feature = "test", feature = "transport_auth"))]
965	impl TransportManager {
966	    pub fn get_auth_handle_unicast(&self) -> Arc<Auth> {
967	        self.state.unicast.authenticator.clone()
968	    }
969	}
