191	    pub async fn close_multicast(&self) {
192	        tracing::trace!("TransportManagerMulticast::clear()");
193	
194	        zasynclock!(self.state.multicast.link_managers).clear();
195	        let mut guard = zasynclock!(self.state.multicast.transports);
196	        let transports = std::mem::take(&mut *guard);
197	        // drop guard: mutex is acquired down the tm.close callstack
198	        drop(guard);
199	        for (_, tm) in transports {
200	            let _ = tm.close(close::reason::GENERIC).await;
201	        }
202	    }
203	
204	    /*************************************/
205	    /*            LINK MANAGER           */
206	    /*************************************/
207	    async fn new_link_manager_multicast(
208	        &self,
209	        endpoint: &EndPoint,
210	    ) -> ZResult<LinkManagerMulticast> {
211	        let link_kind = LinkKind::try_from(endpoint)?;
212	        if !self.config.supported_links.contains(&link_kind) {
213	            bail!(
214	                "Unsupported link: {:?}. Supported links are: {:?}",
215	                link_kind,
216	                self.config.supported_links
217	            );
218	        }
219	
220	        let mut w_guard = zasynclock!(self.state.multicast.link_managers);
221	        match w_guard.get(&link_kind) {
222	            Some(lm) => Ok(lm.clone()),
223	            None => {
224	                let lm = LinkManagerBuilderMulticast::make(link_kind)?;
225	                w_guard.insert(link_kind, lm.clone());
226	                Ok(lm)
227	            }
228	        }
229	    }
