231	    async fn del_link_manager_multicast(&self, link_kind: LinkKind) -> ZResult<()> {
232	        match zasynclock!(self.state.multicast.link_managers).remove(&link_kind) {
233	            Some(_) => Ok(()),
234	            None => bail!(
235	                "Can not delete the link manager for link ({link_kind:?}) because it has not been found."
236	            ),
237	        }
238	    }
239	
240	    /*************************************/
241	    /*             TRANSPORT             */
242	    /*************************************/
243	    pub async fn open_transport_multicast(
244	        &self,
245	        mut endpoint: EndPoint,
246	    ) -> ZResult<TransportMulticast> {
247	        let p = endpoint.protocol();
248	        let link_kind = LinkKind::try_from(&endpoint)?;
249	        if !self.config.supported_links.contains(&link_kind) {
250	            bail!(
251	                "Unsupported protocol: {}. Supported protocols are: {:?}",
252	                p,
253	                self.config.supported_links
254	            );
255	        }
256	        if !self
257	            .locator_inspector
258	            .is_multicast(&endpoint.to_locator())
259	            .await?
260	        {
261	            bail!(
262	                "Can not open a multicast transport with a unicast endpoint: {}.",
263	                endpoint
264	            )
265	        }
266	
267	        // Automatically create a new link manager for the protocol if it does not exist
268	        let manager = self.new_link_manager_multicast(&endpoint).await?;
269	        // Fill and merge the endpoint configuration
270	        if let Some(config) = self
271	            .config
272	            .link_configs
273	            .get(&LinkKind::try_from(&endpoint)?)
274	        {
275	            let mut config = parameters::Parameters::from(config.as_str());
276	            // Overwrite config with current endpoint parameters
277	            config.extend_from_iter(endpoint.config().iter());
278	            endpoint = EndPoint::new(
279	                endpoint.protocol(),
280	                endpoint.address(),
281	                endpoint.metadata(),
282	                config.as_str(),
283	            )?;
284	        }
285	
286	        // Open the link
287	        let link = manager.new_link(&endpoint).await?;
288	        super::establishment::open_link(self, link).await
289	    }
