317	    pub(super) async fn del_transport_multicast(&self, locator: &Locator) -> ZResult<()> {
318	        let mut guard = zasynclock!(self.state.multicast.transports);
319	        let res = guard.remove(locator);
320	        let link_kind = LinkKind::try_from(locator)?;
321	
322	        if !guard
323	            .iter()
324	            .any(|(l, _)| LinkKind::try_from(l).is_ok_and(|k| k == link_kind))
325	        {
326	            let _ = self.del_link_manager_multicast(link_kind).await;
327	        }
328	
329	        res.map(|_| ()).ok_or_else(|| {
330	            let e = zerror!("Can not delete the transport for locator: {}", locator);
331	            tracing::trace!("{}", e);
332	            e.into()
333	        })
334	    }
