336	    /*************************************/
337	    /*              LISTENER             */
338	    /*************************************/
339	    pub async fn add_listener_multicast(&self, endpoint: EndPoint) -> ZResult<Locator> {
340	        let locator = endpoint.to_locator().to_owned();
341	        self.open_transport_multicast(endpoint).await?;
342	        Ok(locator)
343	    }
